import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.nio.file.Path;

public class SecurePathTraversal {

    private static final String BASE_DIRECTORY = "/var/data/";

    public static void main(String[] args) {
        String userInput = "../secretFile.txt"; // User input containing path traversal

        try {
            Path resolvedPath = Paths.get(BASE_DIRECTORY).resolve(userInput).normalize();
            if (!resolvedPath.startsWith(Paths.get(BASE_DIRECTORY))) {
                System.out.println("Invalid path specified");
                return;
            }

            File file = resolvedPath.toFile();
            if (file.exists()) {
                byte[] fileContent = Files.readAllBytes(file.toPath());
                System.out.println(new String(fileContent));
            } else {
                System.out.println("File not found");
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

